command:
mkdir -p pr-corpus && printf '{"event":"generation","patterns_referenced":["p1"]}
' > event.json && printf 'patterns:
  - {id: p1, provenance_class: pr-corpus, supporting_prs: [{number: 1, org: a, tier: 1}]}
' > pr-corpus/patterns-index.yaml && bash "$CLAUDE_PLUGIN_ROOT/pr-corpus/consumption-trace.sh" --event event.json --patterns-index pr-corpus/patterns-index.yaml --out pr-corpus/consumption-trace.jsonl 2>err.txt && grep -q '"provenance_class":"pr-corpus"' pr-corpus/consumption-trace.jsonl && echo ok 1>&2
